const registers = '100,101,102,103,104,105,106,107,108,109,110,111,200,201,202,203,300,301';
const url = 'http://backend:8000/api/sensors/mapping/registers?registers=' + registers;

// 异步获取映射表
fetch(url)
    .then(res => res.json())
    .then(map => {
        const valid = Object.keys(map).length;
        global.set('sensor_map', map);
        node.status({fill:'green', shape:'dot', text:'Mapping: ' + valid + ' registers'});
    })
    .catch(err => {
        node.warn('Failed to load mapping: ' + err.message);
    });

// 发送寄存器读取请求
return registers.split(',').map(addr => ({
    payload: {
        unit: 1,
        fc: 3,
        address: parseInt(addr),
        quantity: 1
    },
    topic: 'modbus/read'
}));

const sensor_map = global.get('sensor_map');
if (!sensor_map) {
    node.warn('Sensor map not loaded yet');
    return null;
}

const addr = String(msg.payload.address);
const val = msg.payload.value;
const meta = sensor_map[addr];
if (!meta) {
    node.warn('Unknown register: ' + addr);
    return null;
}

const value = Math.round((val * meta.factor + meta.offset) * 100) / 100;

return {
    payload: {
        asset_id: meta.asset_id,
        sensor_id: meta.sensor_id,
        measurement: meta.measurement,
        value: value,
        timestamp: new Date().toISOString()
    },
    topic: 'dt/telemetry/' + meta.asset_id
};

const key = msg.payload.sensor_id + '-' + msg.payload.measurement;
const buffer = flow.get(key) || [];
buffer.push(msg.payload.value);
if (buffer.length > 2) buffer.shift();
flow.set(key, buffer);

const smooth_val = buffer.reduce((a, b) => a + b, 0) / buffer.length;
msg.payload.value = Math.round(smooth_val * 100) / 100;
return msg;

const { asset_id, sensor_id, measurement, value } = msg.payload;
const RULES = [
    { sensor_id: 1, name: 'RACK-001 Temp High', threshold: 30, severity: 'warning' },
    { sensor_id: 1, name: 'RACK-001 Temp Crit', threshold: 35, severity: 'critical' },
    { sensor_id: 11, name: 'RACK-003 Hum High', threshold: 70, severity: 'warning' },
    { sensor_id: 3, name: 'RACK-001 PWR High', threshold: 5, severity: 'warning' }
];
const matched = RULES.filter(r => r.sensor_id === sensor_id && value > r.threshold);
if (matched.length > 0) {
    return matched.map(r => ({
        payload: {
            event_id: 'evt_' + Date.now(),
            asset_id,
            sensor_id,
            event_type: 'THRESHOLD_VIOLATION',
            severity: r.severity,
            current_state: r.severity === 'critical' ? 'Alarm' : 'Warning',
            description: r.name + ': ' + value + ' (threshold: ' + r.threshold + ')',
            value,
            timestamp: new Date().toISOString()
        },
        topic: 'industrial_twin/edge_node_01/event/alarm'
    }));
}
return null;
